
-- 建筑设计防火规范条文表
-- Table: fire_code_articles
DROP TABLE IF EXISTS fire_code_articles;
DROP TABLE IF EXISTS fire_code_chapters;

-- 章节表
CREATE TABLE fire_code_chapters (
    id SERIAL PRIMARY KEY,
    chapter_number VARCHAR(20) UNIQUE NOT NULL,
    chapter_title TEXT NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
    updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- 条文表
CREATE TABLE fire_code_articles (
    id SERIAL PRIMARY KEY,
    chapter_id INTEGER REFERENCES fire_code_chapters(id) ON DELETE CASCADE,
    article_number VARCHAR(50) NOT NULL,
    article_content TEXT NOT NULL,
    is_mandatory BOOLEAN DEFAULT FALSE,
    article_type VARCHAR(50),
    keywords TEXT[],
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
    updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- 创建索引
CREATE INDEX idx_fire_code_articles_number ON fire_code_articles(article_number);
CREATE INDEX idx_fire_code_articles_mandatory ON fire_code_articles(is_mandatory);
CREATE INDEX idx_fire_code_articles_type ON fire_code_articles(article_type);
CREATE INDEX idx_fire_code_articles_chapter ON fire_code_articles(chapter_id);
CREATE INDEX idx_fire_code_articles_keywords ON fire_code_articles USING GIN(keywords);

-- 添加注释
COMMENT ON TABLE fire_code_chapters IS '规范章节表';
COMMENT ON TABLE fire_code_articles IS '规范条文表';
COMMENT ON COLUMN fire_code_articles.article_number IS '条文编号，如1.0.1';
COMMENT ON COLUMN fire_code_articles.article_content IS '条文内容';
COMMENT ON COLUMN fire_code_articles.is_mandatory IS '是否为强制性条文';
COMMENT ON COLUMN fire_code_articles.article_type IS '条文类型';
COMMENT ON COLUMN fire_code_articles.keywords IS '关键词数组，用于全文搜索';


