INSERT INTO fire_code_chapters (chapter_number, chapter_title) VALUES
('1', '总 则'),
('10', '电 气'),
('11', '木结构建筑'),
('12', '城市交通隧道'),
('122', '消防给水和灭火设施'),
('13', '设置机械排烟、防烟系统,雨淋或预作用自动喷水灭 火系统,固定消防水炮灭火系统、气体灭火系统等需与火灾自 动报警系统联锁动作的场所或部位。'),
('2', '不同液体、不同形式储罐之间的防火间距不应小于本表规定的较大值。'),
('2018', '北 京'),
('27', '混凝'),
('3', '厂房和仓库'),
('4', '独立建造的硝酸铵仓库、电石仓库、聚乙烯等高分子制品仓库、尿素仓库、'),
('5', '耐火等级低于四级的既有厂房,其耐火等级可按四级确定。'),
('6', '含油污水排水管应在防火堤的出口处设置水封设施, 雨水排水管应设置阀门等封闭、隔离装置。'),
('62', '建筑构件和管道井'),
('7', '城市交通隧道。'),
('8', '应设置与锅炉、变压器、电容器和多油开关等的容量及 建筑规模相适应的灭火设施,当建筑内其他部位设置自动喷水 灭火系统时,应设置自动喷水灭火系统。'),
('9', '步行街两侧建筑的商铺内外均应设置疏散照明、灯光 疏散指示标志和消防应急广播系统。')
